                  import sailpoint.tools.Util;
                  import sailpoint.object.Identity;

                  public String getStringData(List list){
                  	String result = "";
                 		try{
                  		if(!Util.isEmpty(list)){
                  			for(String item : list){
                  				if(Util.isNotNullOrEmpty(item)){
                  					item = item.replaceAll("'","''");
                  					if(Util.isNullOrEmpty(result)){
                  						result = "'"+item.trim()+"'";
                  					}else{
                  						result = result + ",'" +item.trim()+ "'";
                  					}
                  				}	
                  			}
                  		}
                  	}catch(Exception ex){
                  		log.error("Exception in Report "+ex.getMessage());
                  	}

                  	return result;
                  }
									
                  query = query 
                  				+ " ("  
                  				+ "	(CAST(idn.lastHireDate as date) > CONVERT (date, GETDATE()) or CAST(idn.lastHireDate as date) >=  CONVERT (date, GETDATE() - 30)) or"  
                  				+ "	(" 
                  				+ "		(TRY_CONVERT(DATE, idn.hireDate) > CONVERT (date, GETDATE()) or TRY_CONVERT(DATE, idn.hireDate) >=  CONVERT (date, GETDATE() - 30))" 
                  				+ "	)" 
                 					+ ")" 
                  				+ " and (" 
                 					+ " 		(" 
                  				+ " 			idn.ministry!='AMITA Health' and idn.type in (" +getStringData(args.get("type"))+ ")" 
                  				+ " 		) or" 
                  				+ " 		(" 
                  				+ " 			idn.ministry!='AMITA Health' and (idn.personaType='Primary' or idn.personaType='') and idn.type in (" +getStringData(args.get("type"))+ ")" 
                  				+ "			)" 
                  				+ "			)" 
                  			;

                  return query;

