                    import sailpoint.object.Identity;
                    import sailpoint.object.Application;
                    import sailpoint.api.IdentityService;
                    import sailpoint.object.Link;
                    import sailpoint.tools.Util;

                    Identity identityObj = context.getObject(Identity.class, value);
                    Application appObj = context.getObject(Application.class, "DB-Peoplesoft-HCM-Primary");
                    IdentityService is = new IdentityService(context);

                    List links = is.getLinks(identityObj, appObj);
                    if(Util.nullSafeSize(links) > 0) {
                    	Link link = links.get(0);
                    	return link.getAttribute("EFFDT");
                    }
                    return "";

				  
