                    import sailpoint.object.Identity;
                    import sailpoint.tools.Util;

                    Identity identityObj = context.getObject(Identity.class, value);
                    if(identityObj != null @and identityObj.getManager() != null){
                   
                    Identity managerObj = identityObj.getManager();
                    
                    String managerFN = managerObj.getFirstname() != null ? managerObj.getFirstname() : "";
                    String managerLN = managerObj.getLastname() != null ? managerObj.getLastname() : "";
										
                    return managerFN+" "+managerLN;
                    }
