                    import sailpoint.object.Identity;
                    import sailpoint.object.Custom;
                    import sailpoint.object.Link;
                    import org.ascn.utils.GeneralUtils;
                    import sailpoint.tools.Util;

                    String customObjName = "ASCN-Ministry-Domain-Mapping";
                    Identity identityObj = context.getObject(Identity.class, value);
                    String strMinistry = identityObj.getAttribute("ministry");

                    List domainVals = GeneralUtils.loadCustomList(strMinistry, customObjName);
                    if(Util.nullSafeSize(domainVals) > 0) {

                    	if(domainVals.size() == 1){
                    		return domainVals.get(0);
                    	}else{
                  			return "";
                    	}
                    }
                    return "";

				  
